import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.provider.MediaStore
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        
        handleShareIntent()
    }
    
    private fun handleShareIntent() {
        val intent = intent
        if (Intent.ACTION_SEND == intent.action && intent.type != null) {
            if ("text/plain" == intent.type || "image/*" == intent.type) {
                handleSendText(intent)
            } 
        }
    }
    
    private fun handleSendText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        
        if (sharedText != null && sharedText.startsWith("http")){
            Toast.makeText(this, "Shared URL: $sharedText", Toast.LENGTH_LONG).show()
        } else {
            handleImageShare(intent)
        }
    }
    
    private fun handleImageShare(intent: Intent) {
        val imageUri = intent.data
        
        try {
            val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, imageUri)
            processSharedImage(bitmap)
        } catch (e: IOException) {
            e.printStackTrace()
        } 
    }
    
